import api from './api';

export default {
  /**
   * Get all novels
   * @returns {Promise} Promise containing all novels
   */
  getAllNovels() {
    return api.get('/novels');
  },
  
  /**
   * Get novel by ID
   * @param {number} id - The novel ID
   * @returns {Promise} Promise containing the novel data
   */
  getNovelById(id) {
    return api.get(`/novels/${id}`);
  },
  
  /**
   * Get novel status
   * @param {number} id - The novel ID
   * @returns {Promise} Promise containing the processing status
   */
  getNovelStatus(id) {
    return api.get(`/novels/${id}/status`);
  },
  
  /**
   * Upload a novel file
   * @param {FormData} formData - Form data containing the file and metadata
   * @returns {Promise} Promise containing the upload result
   */
  uploadNovel(formData) {
    return api.post('/novels/upload', formData, {
      headers: {
        'Content-Type': 'multipart/form-data'
      }
    });
  },
  
  /**
   * Get chapters of a novel
   * @param {number} novelId - The novel ID
   * @returns {Promise} Promise containing the chapters
   */
  getChapters(novelId) {
    return api.get(`/novels/${novelId}/chapters`);
  },
  
  /**
   * Get tags of a novel
   * @param {number} novelId - The novel ID
   * @returns {Promise} Promise containing the tags
   */
  getTags(novelId) {
    return api.get(`/novels/${novelId}/tags`);
  },
  
  /**
   * Delete a novel
   * @param {number} id - The novel ID
   * @returns {Promise} Promise containing the deletion result
   */
  deleteNovel(id) {
    return api.delete(`/novels/${id}`);
  }
};
